$\begin{align}
\dfrac{d}{dy}\left[\ln (20y^3+5)+C\right]&=\dfrac{60y^2}{20y^3+5}\\\\
&=\dfrac{12y^2}{4y^3+1}
\\\\
\dfrac{d}{dy}\left[\ln (5y^4+1)+C\right]&=\dfrac{20y^3}{5y^4+1}
\\\\
\dfrac{d}{dy}\left[\ln(y^5+y )+C\right]&=\dfrac{5y^4+1}{y^5+y}
\end{align}$

$\begin{align}
\dfrac{d}{dx}\left[\ln(4x-8)+C\right]&=\dfrac{4}{4x-8}
\\\\
&=\dfrac{1}{x-2}
\\\\
\dfrac{d}{dx}\left[\ln(4x^4-8)+C\right]&=\dfrac{16x^3}{4x^4-8}
\\\\
&=\dfrac{4x^3}{x^4-2}
\\\\
\dfrac{d}{dx}\left[\ln(4x)+C\right]&=\dfrac{4}{4x}
\\\\
&=\dfrac{1}{x}
\end{align}$

$\begin{align}
\dfrac{d}{dz}\left[\ln(6z^4+3z^2)+C\right]&=\dfrac{24z^3+6z}{6z^4+3z^2}
\\\\
&=\dfrac{8z^2+2}{2z^3+z}
\\\\
\dfrac{d}{dz}\left[\ln(6z^2+3z)+C\right]&=\dfrac{12z+3}{6z^2+3z}
\\\\
&=\dfrac{4z+1}{2z^2+z}
\\\\
\dfrac{d}{dz}\left[\ln(4z+1)+C\right]&=\dfrac{4}{4z+1}
\end{align}$

$\begin{align}
\dfrac{d}{dt}\left[\ln(12t^2-12 )+C\right]&=\dfrac{24t}{12t^2-12}
\\\\
&=\dfrac{2t}{t^2-1}
\\\\
\dfrac{d}{dt}\left[\ln (t^4-6t^2) +C\right]&=\dfrac{4t^3-12t}{t^4-6t^2}
\\\\
&=\dfrac{4t^2-12}{t^3-6t}
\\\\
\dfrac{d}{dt}\left[\ln (4t^3-12t)+C\right]&=\dfrac{12t^2-12}{4t^3-12t}
\\\\
&=\dfrac{3t^2-3}{t^3-3t}
\end{align}$
